SET client_encoding = 'UTF8';
-- ================================================================
-- PASO 1: Reconstruir tablas desde cero
-- ================================================================
DROP TABLE IF EXISTS Asignacion CASCADE;
DROP TABLE IF EXISTS Vehiculo CASCADE;
DROP TABLE IF EXISTS Materia CASCADE;
DROP TABLE IF EXISTS Docente CASCADE;
DROP TABLE IF EXISTS Carrera CASCADE;
CREATE TABLE Carrera (carrera_id INT PRIMARY KEY, nombre VARCHAR(100), siglas VARCHAR(10));
CREATE TABLE Docente (docente_id SERIAL PRIMARY KEY, nombre VARCHAR(255) NOT NULL, rfc VARCHAR(50), curp VARCHAR(50), grado_acad VARCHAR(50), grado_mil VARCHAR(50), condicion VARCHAR(50) DEFAULT 'Personal Civil', genero VARCHAR(10), domicilio TEXT, credencial_ine VARCHAR(50), tipo_sangre VARCHAR(10), estado_evaluacion VARCHAR(50) DEFAULT 'Pendiente');
CREATE TABLE Materia (materia_id SERIAL PRIMARY KEY, nombre VARCHAR(255) NOT NULL, carrera_id INT REFERENCES Carrera(carrera_id));
CREATE TABLE Vehiculo (vehiculo_id SERIAL PRIMARY KEY, docente_id INT REFERENCES Docente(docente_id), marca VARCHAR(50), modelo VARCHAR(80), anio VARCHAR(10), color VARCHAR(50), placas VARCHAR(20));
CREATE TABLE Asignacion (asignacion_id SERIAL PRIMARY KEY, docente_id INT REFERENCES Docente(docente_id), materia_id INT REFERENCES Materia(materia_id));
